const text = $input.first().json.output[0].content[0].text;

const clean = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

const parsed = JSON.parse(clean);

return [{ json: parsed }];

// Einfaches IP-basiertes Rate Limiting via Static Data
const staticData = $getWorkflowStaticData('global');
const ip = $input.first().json.headers['x-forwarded-for'] || 'unknown';
const now = Date.now();
const windowMs = 24 * 60 * 60 * 1000; // 24 Stunden
const maxRequests = 3; // Max 3 Anfragen pro IP pro Tag

if (!staticData.ipLog) staticData.ipLog = {};

// Alte Einträge bereinigen
for (const key of Object.keys(staticData.ipLog)) {
  if (now - staticData.ipLog[key].start > windowMs) {
    delete staticData.ipLog[key];
  }
}

if (!staticData.ipLog[ip]) {
  staticData.ipLog[ip] = { count: 1, start: now };
} else if (staticData.ipLog[ip].count >= maxRequests) {
  throw new Error('Rate limit exceeded');
} else {
  staticData.ipLog[ip].count++;
}

return $input.all();
